Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` — no port, no real server.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
```

### Example test

```csharp
public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first
        await InitializeAsync();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };
        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeAsync()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

### Key points

- **No real port** — `WebApplicationFactory` uses an in-memory `TestServer` under the hood.
- **Override services** if needed (e.g., swap a database for a fake):
  ```csharp
  factory.WithWebHostBuilder(builder =>
      builder.ConfigureServices(services =>
          services.AddSingleton<IMyDep, FakeMyDep>()));
  ```
- **SSE transport**: If your server uses SSE, use `factory.CreateClient()` with `HttpCompletionOption.ResponseHeadersRead` and read the stream line-by-line to assert SSE events.
- Make `Program` visible to the test project by adding `[assembly: InternalsVisibleTo("MyMcp.Tests")]` or a `public partial class Program { }` at the bottom of `Program.cs`.

This gives you full HTTP-level integration tests against the real MCP JSON-RPC protocol with zero network overhead.
